class ConfigurationsController < ApplicationController
  def new
  end

  def create
    if params[:config_file].present?
      begin
        yaml_content = params[:config_file].read
        @parsed_config = YAML.load(yaml_content)

        flash[:success] = "Configuration imported successfully!"
        render :create
      rescue Psych::SyntaxError => e
        flash[:error] = "Error parsing YAML file: #{e.message}"
        render :new, status: :unprocessable_entity
      rescue ArgumentError => e
        flash[:error] = "Invalid YAML content: #{e.message}"
        render :new, status: :unprocessable_entity
      rescue => e
        flash[:error] = "An unexpected error occurred: #{e.message}"
        render :new, status: :unprocessable_entity
      end
    else
      flash[:error] = "Please select a YAML file to upload."
      render :new, status: :unprocessable_entity
    end
  end
end

